@using sv_dbc7fca240984671ad8e944535b5dc2c.Services

<div class="message-bubble" @onmouseenter="() => showActions = true" @onmouseleave="() => showActions = false">
    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <ReactionBar Reactions="Message.Reactions" OnReactionClicked="HandleReaction" />
    }

    @if (ReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (showActions)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)" title="Reply in thread">
                💬 Reply
            </button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">
                🙂 React
            </button>
        </div>
    }

    @if (showEmojiPicker)
    {
        <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool showActions;
    private bool showEmojiPicker;

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task HandleEmojiSelected(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private async Task HandleReaction(string emoji)
    {
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        return diff.TotalMinutes switch
        {
            < 1 => "just now",
            < 60 => $"{(int)diff.TotalMinutes} min ago",
            < 1440 => $"{(int)diff.TotalHours}h ago",
            _ => $"{(int)diff.TotalDays}d ago"
        };
    }
}

@using sv_dbc7fca240984671ad8e944535b5dc2c.Services

<aside class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == SelectedChannelId"
                         OnClick="() => OnChannelSelected.InvokeAsync(channel.Id)" />
        }
    </div>
</aside>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

@using sv_dbc7fca240984671ad8e944535b5dc2c.Services
@inject IJSRuntime JS

<div class="message-list" @ref="scrollContainer" @onscroll="HandleScroll">
    @if (IsLoadingMore)
    {
        <div class="loading-indicator">Loading older messages…</div>
    }
    @foreach (var message in Messages)
    {
        <MessageBubble Message="message"
                       ReplyCount="GetReplyCount(message.Id)"
                       OnOpenThread="OnOpenThread"
                       OnReact="OnReact" />
    }
</div>

@code {
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private ElementReference scrollContainer;
    private bool loadingTriggered;

    private int GetReplyCount(int messageId) =>
        ThreadReplyCounts.TryGetValue(messageId, out var count) ? count : 0;

    private async Task HandleScroll()
    {
        if (loadingTriggered) return;

        var scrollTop = await JS.InvokeAsync<double>("eval",
            $"document.querySelector('.message-list')?.scrollTop ?? 1");

        if (scrollTop < 50)
        {
            loadingTriggered = true;
            await OnLoadMore.InvokeAsync();
            loadingTriggered = false;
        }
    }
}

