@page "/chat"
@using sv_dbc7fca240984671ad8e944535b5dc2c.Services
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout @(threadOpen ? "thread-open" : "")">
    <ChannelSidebar Channels="channels"
                    SelectedChannelId="selectedChannelId"
                    OnChannelSelected="SelectChannel" />

    @if (selectedChannel is not null)
    {
        <MessageArea ChannelName="@selectedChannel.Name"
                     ChannelDescription="@selectedChannel.Description"
                     Messages="messages"
                     ThreadReplyCounts="threadReplyCounts"
                     IsLoadingMore="isLoadingMore"
                     OnLoadMore="LoadOlderMessages"
                     OnOpenThread="OpenThread"
                     OnReact="HandleReaction"
                     OnSendMessage="SendMessage" />
    }

    @if (threadOpen)
    {
        <ThreadPanel RootMessage="threadRootMessage"
                     Replies="threadReplies"
                     OnClose="CloseThread"
                     OnSendReply="SendThreadReply"
                     OnReact="HandleReaction" />
    }
</div>

@code {
    private List<Channel> channels = [];
    private List<Message> messages = [];
    private List<Message> threadReplies = [];
    private Dictionary<int, int> threadReplyCounts = [];
    private int selectedChannelId;
    private Channel? selectedChannel;
    private Message? threadRootMessage;
    private bool threadOpen;
    private bool isLoadingMore;
    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        selectedChannelId = channelId;
        selectedChannel = channels.FirstOrDefault(c => c.Id == channelId);
        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        BuildThreadReplyCounts();
        CloseThread();
        await ChatService.MarkChannelReadAsync(channelId);

        // Refresh channel list to clear unread badge
        channels = await ChatService.GetChannelsAsync();
    }

    private async Task LoadOlderMessages()
    {
        if (isLoadingMore) return;
        isLoadingMore = true;

        var older = await ChatService.GetMessagesAsync(selectedChannelId, messages.Count, PageSize);
        if (older.Count > 0)
        {
            messages.InsertRange(0, older);
            BuildThreadReplyCounts();
        }

        isLoadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        var msg = await ChatService.SendMessageAsync(selectedChannelId, content, null);
        messages.Add(msg);
    }

    private async Task OpenThread(int rootMessageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        threadOpen = true;
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (threadRootMessage is null) return;
        var reply = await ChatService.SendMessageAsync(selectedChannelId, content, threadRootMessage.Id);
        threadReplies.Add(reply);

        // Update reply count in the main message list
        threadReplyCounts[threadRootMessage.Id] =
            threadReplyCounts.GetValueOrDefault(threadRootMessage.Id) + 1;
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh messages to reflect the new reaction
        messages = await ChatService.GetMessagesAsync(selectedChannelId, 0, messages.Count);

        if (threadOpen && threadRootMessage is not null)
        {
            threadReplies = await ChatService.GetThreadAsync(threadRootMessage.Id);
            threadRootMessage = messages.FirstOrDefault(m => m.Id == threadRootMessage.Id);
        }
    }

    private void BuildThreadReplyCounts()
    {
        threadReplyCounts = messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(g => g.Key, g => g.Count());
    }
}

